use strict;
use warnings;

sub fibonacci_iterative {
    my ($n) = @_;
    return $n if $n <= 1;

    my ($a, $b) = (0, 1);
    for (2 .. $n) {
        ($a, $b) = ($b, $a + $b);
    }
    return $b;
}

sub fibonacci_recursive {
    my ($n) = @_;
    return $n if $n <= 1;
    return fibonacci_recursive($n - 1) + fibonacci_recursive($n - 2);
}

print "Iteratif Fibonacci (0-10):\n";
print join(" ", map { fibonacci_iterative($_) } 0 .. 10) . "\n";

print "\nRecursive Fibonacci (0-10):\n";
print join(" ", map { fibonacci_recursive($_) } 0 .. 10) . "\n";

print "\n20. Fibonacci sayisi: " . fibonacci_iterative(20) . "\n";
